import React, { useState } from 'react';
import axios from 'axios';
import MapDisplay from './components/MapDisplay';
import SafetyIndicators from './components/SafetyIndicators';
import SOSButton from './components/SOSButton';
import './App.css';
import { MapPinIcon, MagnifyingGlassIcon } from '@heroicons/react/24/solid';

function App() {
  const [source, setSource] = useState('');
  const [destination, setDestination] = useState('');
  const [sourceCoords, setSourceCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [loading, setLoading] = useState(false);
  const [routeFound, setRouteFound] = useState(false);
  const [safeWaypoints, setSafeWaypoints] = useState([]);

  const geocode = async (place) => {
    try {
      const res = await axios.get(`https://nominatim.openstreetmap.org/search`, {
        params: { q: place, format: 'json', limit: 1 },
      });
      if (res.data.length > 0) {
        return { lat: parseFloat(res.data[0].lat), lng: parseFloat(res.data[0].lon) };
      }
    } catch (err) { console.error("Geocoding error:", err); }
    return null;
  };

  const handleFindRoute = async () => {
    if (!source.trim() || !destination.trim()) return alert('Please enter both locations');
    setLoading(true);
    setRouteFound(false);

    try {
      const src = await geocode(source);
      const dest = await geocode(destination);

      if (!src || !dest) {
        setLoading(false);
        return alert('Could not find coordinates for these locations.');
      }

      setSourceCoords(src);
      setDestinationCoords(dest);

      // OSRM API: Fetches the ACTUAL road path instead of a straight line
      const routeUrl = `https://router.project-osrm.org/route/v1/driving/${src.lng},${src.lat};${dest.lng},${dest.lat}?overview=full&geometries=geojson`;
      const routeRes = await axios.get(routeUrl);
      
      if (routeRes.data.routes && routeRes.data.routes.length > 0) {
        const roadPoints = routeRes.data.routes[0].geometry.coordinates.map(coord => ({
          lat: coord[1],
          lng: coord[0]
        }));
        setSafeWaypoints(roadPoints);
        setRouteFound(true);
      }

      // Optional: Send to your backend for safety analysis
      await axios.post('http://localhost:3002/getSafeRoute', { source: src, destination: dest });

    } catch (error) {
      console.error("Routing error:", error);
      alert("Routing failed. Ensure you are connected to the internet.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ position: 'relative', height: '100vh', width: '100vw', overflow: 'hidden', backgroundColor: '#f3f4f6' }}>
      
      <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
         <MapDisplay waypoints={safeWaypoints} source={sourceCoords} destination={destinationCoords} /> 
      </div>

      <div style={{ 
        position: 'absolute', top: '24px', left: '24px', zIndex: 10,
        width: '300px', backgroundColor: 'rgba(255, 255, 255, 0.98)',
        padding: '16px', borderRadius: '12px', boxShadow: '0 4px 20px rgba(0,0,0,0.15)',
        boxSizing: 'border-box'
      }}>
        
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: '16px', gap: '10px' }}>
          <img 
            src={process.env.PUBLIC_URL + '/Logo.jpeg'} 
            alt="S" 
            style={{ height: '32px', width: '32px', borderRadius: '50%', objectFit: 'cover' }}
            onError={(e) => e.target.src = 'https://ui-avatars.com/api/?name=S&background=7c3aed&color=fff'}
          />
          <div>
            <h1 style={{ fontSize: '16px', fontWeight: '900', margin: 0, color: '#111' }}>SheRoute</h1>
            <p style={{ fontSize: '8px', fontWeight: 'bold', color: '#999', textTransform: 'uppercase', margin: 0 }}>Safety Navigator</p>
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          <div style={{ position: 'relative', width: '100%' }}>
            <MapPinIcon style={{ position: 'absolute', left: '10px', top: '50%', transform: 'translateY(-50%)', height: '14px', width: '14px', color: '#9ca3af' }} />
            <input
              type="text"
              placeholder="Start point..."
              value={source}
              onChange={(e) => setSource(e.target.value)}
              style={{ width: '100%', boxSizing: 'border-box', padding: '8px 10px 8px 32px', borderRadius: '8px', border: '1px solid #e5e7eb', fontSize: '12px', outline: 'none' }}
            />
          </div>

          <div style={{ position: 'relative', width: '100%' }}>
            <MapPinIcon style={{ position: 'absolute', left: '10px', top: '50%', transform: 'translateY(-50%)', height: '14px', width: '14px', color: '#db2777' }} />
            <input
              type="text"
              placeholder="Destination..."
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              style={{ width: '100%', boxSizing: 'border-box', padding: '8px 10px 8px 32px', borderRadius: '8px', border: '1px solid #e5e7eb', fontSize: '12px', outline: 'none' }}
            />
          </div>

          <button
            onClick={handleFindRoute}
            disabled={loading}
            style={{ 
              width: '100%', padding: '10px', backgroundColor: '#111', color: '#fff', 
              borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', border: 'none',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', fontSize: '11px'
            }}
          >
            <MagnifyingGlassIcon style={{ height: '14px', width: '14px' }} />
            {loading ? 'SEARCHING...' : 'FIND SAFE ROUTE'}
          </button>
        </div>

        {routeFound && (
          <div style={{ marginTop: '16px', paddingTop: '16px', borderTop: '1px solid #f3f4f6' }}>
             <SafetyIndicators />
          </div>
        )}
      </div>

      <SOSButton />
    </div>
  );
}

export default App;
